    default=False,
    help="Deprecated / unused",
)
@click.option(
    "--umask",
    callback=click_octal,
    default="066",
    help="Set umask for newly created files. Defaults to files with read-write "
    "for owner and nothing for group & others",
)
@click.option(
    "-v",
