@cli.command("ssh")
@click.option(
    "--key",
    "-k",
    help="Path and key of the SSH private key in the vault. Format: `path:key`.",
    required=True,
)
@click.option(
    "--passphrase",
    "-p",
    help="Path and key of the SSH private key passphrase in the vault. Format: `path:key`.",
)
@click.argument("command", nargs=-1, required=True)
@click.pass_obj
@handle_errors()
def ssh_(
    client_obj: client.VaultClientBase,
    key: str,
    passphrase: Optional[str],
    command: Sequence[str],
) -> NoReturn:
    """
    Launch a command, with a configured ssh-agent running.

    The ssh agent has all the keys specified as `--key` arguments.

    The effect will be that any command launched through this wrapper will "magically"
    (thanks to ssh-agent) be able to use the secret keys given as `--key` for their
    ssh connections.
    """
    ssh.ensure_agent()

    if ":" not in key:
        raise click.UsageError("Format for private_key: `path/to/private_key:key`")
    private_key_name, private_key_key = key.rsplit(":", 1)
    private_key_secret_obj = client_obj.get_secret(private_key_name, private_key_key)
    private_key_secret = ensure_str(secret=private_key_secret_obj, path=key)

    passphrase_secret = None
    if passphrase:
        if ":" not in passphrase:
            raise click.UsageError("Format for passphrase: `path/to/passphrase:key`")
        passphrase_name, passphrase_key = passphrase.rsplit(":", 1)
        passphrase_secret_obj = client_obj.get_secret(passphrase_name, passphrase_key)
        passphrase_secret = ensure_str(secret=passphrase_secret_obj, path=passphrase)

    ssh.add_key(key=private_key_secret, passphrase=passphrase_secret)

    environment.exec_command(command=command)


def ensure_str(secret, path) -> str:
    if not isinstance(secret, str):
        raise exceptions.VaultWrongType(
            f"secret at {path} is not a string but {type(secret)}"
        )
    return secret


# This is purposedly not called as a click subcommand, and we cannot take any argument
def askpass():
    print(os.environ[ssh.SSH_PASSPHRASE_ENVVAR])


def main():
    if ssh.SSH_PASSPHRASE_ENVVAR in os.environ:
        return askpass()

    # https://click.palletsprojects.com/en/7.x/python3/
    os.environ.setdefault("LC_ALL", "C.UTF-8")
    os.environ.setdefault("LANG", "C.UTF-8")

    return cli()

import json
import logging
import os
import pathlib
import re
from typing import Dict, Mapping, NoReturn, Optional, Sequence

from vault_cli import client, exceptions, types

logger = logging.getLogger(__name__)

_replaced_by_underscore = re.compile(r"[/\- ]")
_allowed_named = re.compile(r"[A-Z0-9_]+")


def _normalize(name: str) -> str:
    """
    Change " ", "-" and "/" into "_" in a string
    """
    envvar_name = _replaced_by_underscore.sub("_", name).upper()

    if not _allowed_named.fullmatch(envvar_name):
        raise exceptions.VaultInvalidEnvironmentName(envvar_name)

    return envvar_name


def _make_env_value(value: types.JSONValue) -> str:
    if isinstance(value, str):
        return value
    return json.dumps(value)


def full_environment(environment: Mapping[str, str]) -> Mapping[str, str]:
    current_env = os.environ.copy()
    current_env.update(environment)
    return current_env


def exec_command(
    command: Sequence[str], environment: Optional[Mapping[str, str]] = None
) -> NoReturn:
    environment = full_environment(environment or {})
    os.execvpe(command[0], tuple(command), environment)


def get_envvars_for_secrets(
    secrets: Dict[str, types.JSONDict],
    path: str,
    prefix: str,
    omit_single_key: bool = False,
) -> Dict[str, str]:
    env_secrets = {}
    if not prefix:
        prefix = pathlib.Path(path).name

    for subpath, values in secrets.items():
        omit = omit_single_key and len(values) == 1
        for key, value in values.items():
            if omit:
                key = ""
            try:
                env_name = _normalize("_".join(e for e in (prefix, subpath, key) if e))
            except exceptions.VaultInvalidEnvironmentName as exc:
                logger.warning(f"Invalid environment name {exc}, skipping secret value")
                continue
            value = _make_env_value(value)
            env_secrets[env_name] = value
    return env_secrets


def get_envvars(
    vault_client: client.VaultClientBase,
    path: str,
    prefix: str,
    omit_single_key: bool,
    filter_key: str,
) -> Dict[str, str]:
    if filter_key:
        secret = vault_client.get_secret(path=path, key=filter_key)
        return get_envvars_for_secrets(
            path="",
            prefix=prefix,
            secrets={"": {filter_key: secret}},
            omit_single_key=bool(prefix),
        )
    else:
        secrets = vault_client.get_secrets(path=path, relative=True)
        return get_envvars_for_secrets(
            path=path, prefix=prefix, secrets=secrets, omit_single_key=omit_single_key
        )

import logging
import os
import sys
from functools import lru_cache
from typing import Dict, Optional, Union

import yaml

from vault_cli import exceptions, types

logger = logging.getLogger(__name__)

ENV_PREFIX = "VAULT_CLI"

# Ordered by increasing priority
CONFIG_FILES = ["./vault.yml", "~/.vault.yml", "/etc/vault.yml"]


class DEFAULTS:
    base_path = None
    login_cert = None
    login_cert_key = None
    password = None
    token = None
    url = "http://localhost:8200"
    username = None
    verify = True
    ca_bundle = None
    safe_write = False

    @staticmethod
    def _as_dict():
        return {k: v for k, v in vars(DEFAULTS).items() if k[0] != "_"}


def read_config_file(file_path: str) -> Optional[types.SettingsDict]:
    try:
        with open(os.path.expanduser(file_path), "r") as f:
            config = yaml.safe_load(f) or {}
            logger.info(
                f"Reading yaml config file at {file_path}, "
                f"contains keys: {', '.join(config)}"
            )
            return config
    except FileNotFoundError:
        logger.debug(f"No config file at {file_path} (skipping)")
    except IOError:
        logger.warning(
            f"Config file exists at {file_path}, but cannot be read. "
            "Have you checked permissions? (skipping)"
        )

    return None


def dash_to_underscores(config: types.SettingsDict) -> types.SettingsDict:
    # Because we're modifying the dict during iteration, we need to
    # consolidate the keys into a list
    return {key.replace("-", "_"): value for key, value in config.items()}


def load_bool(value: str) -> bool:
    lower_value = value.lower()

    if lower_value in ("true", "t", "1", "yes", "y"):
        return True
    elif lower_value in ("false", "f", "0", "no", "n"):
        return False

    raise exceptions.VaultSettingsError("Value {} could not be interpreted as boolean")


def build_config_from_env(environ: Dict[str, str]) -> types.SettingsDict:
    result: types.SettingsDict = {}

    skip_len = len(ENV_PREFIX) + 1

    value: Union[str, bool]

    defaults_dict = DEFAULTS._as_dict()

    for key, str_value in environ.items():

        if not key.startswith(ENV_PREFIX + "_"):
            continue

        key = key[skip_len:].lower()

        if key not in defaults_dict:
            continue

        if isinstance(defaults_dict[key], bool):
            value = load_bool(str_value)
        else:
            value = str_value

        result[key] = value

    return result


def read_all_files(config: types.SettingsDict) -> types.SettingsDict:
    config = config.copy()

    replace_path_with_content(config=config, setting_name="password")
    replace_path_with_content(config=config, setting_name="token")

    return config


def replace_path_with_content(config: types.SettingsDict, setting_name: str) -> None:
    """
    Modifies config dict in place: reads the file at <setting_name>_file
    and put its contents at <setting_name> instead.
    """
    # Files override direct values when both are defined
    filename = config.pop(f"{setting_name}_file", None)
    if filename:
        assert isinstance(filename, str)
        logger.info(f"Reading value of '{setting_name}' from file {filename}")
        config[setting_name] = read_file(filename)


def read_file(path: str) -> Optional[str]:
    """
    Returns the content of the pointed file
    """
    if path == "-":
        return sys.stdin.read().strip()

    with open(os.path.expanduser(path)) as file_handler:

        return file_handler.read().strip()


@lru_cache()
def build_config_from_files(*config_files: str):
    values = DEFAULTS._as_dict()

    for potential_file in config_files:
        file_config = read_config_file(potential_file)
        if file_config is not None:
            file_config = dash_to_underscores(file_config)
            file_config = read_all_files(file_config)
            values.update(file_config)
            break

    return values


def get_vault_options(*, config_file: Optional[str] = None, **kwargs: types.Settings):
    config_files = [config_file] if config_file else CONFIG_FILES
    values = build_config_from_files(*config_files).copy()
    values.update(build_config_from_env(os.environ.copy()))
    values.update(kwargs)

    return values


def get_log_level(verbosity: int) -> int:
    """
    Given the number of repetitions of the flag -v,
    returns the desired log level
    """
    return {0: logging.WARNING, 1: logging.INFO, 2: logging.DEBUG}.get(
        min((2, verbosity)), 0
    )

