        crayons.yellow("pipenv lock --pre"),
        crayons.yellow("pipenv graph"),
        crayons.yellow("pipenv check"),
        crayons.yellow("pipenv install -e ."),
        crayons.yellow("pipenv run pip freeze"),
    )
    help = help.replace("Commands:", additional_help)
